import streamlit as stimport pandas as pdimport plotly.express as pximport time# --- 1. YAPILANDIRMA VE STİL ---st.set_page_config(page_title="Focus AI - Bostanlı Çözüm VIP", layout="wide")st.markdown("""    <style>    .main { background-color: #0f172a; color: #f8fafc; }    .stMetric { background-color: #1e293b; padding: 15px; border-radius: 12px; border: 1px solid #334155; }    .stButton>button { border-radius: 10px; background: linear-gradient(90deg, #2563eb, #3b82f6); border: none; color: white; }    .stDownloadButton>button { border-radius: 10px; background: #059669; color: white; border: none; }    .report-card { background: #1e293b; padding: 15px; border-left: 5px solid #ef4444; border-radius: 10px; }    .warning-box { background-color: #450a0a; padding: 10px; border-radius: 8px; border: 1px solid #f87171; color: #fecaca; margin-bottom: 10px; }    </style>    """, unsafe_allow_html=True)# --- 2. AI MOTORU ---def calculate_detailed_score(data):    """TYT %40 - AYT %60 Ağırlıklı Puan Tahmini"""    tyt = (data.get('TYT_Mat', 0)*3.3) + (data.get('TYT_Turkce', 0)*3.3) + \          (data.get('TYT_Sosyal', 0)*3.4) + (data.get('TYT_Fen', 0)*3.4)        ayt = (data.get('AYT_Mat', 0)*3.0) + (data.get('AYT_Fizik', 0)*2.85) + \          (data.get('AYT_Kimya', 0)*3.07) + (data.get('AYT_Biyoloji', 0)*3.07)        return round(100 + (tyt * 0.4) + (ayt * 0.6), 2)# --- 3. PANELLER ---def login_screen():    st.title("🛡️ Focus AI Giriş")    user = st.selectbox("Yetki", ["ADMIN", "KOC", "OGRENCI"])    if st.button("Giriş"):        st.session_state.role = user        st.rerun()def admin_panel():    st.title("🏢 Kurum Yönetim Merkezi")        st.subheader("📥 Veri Aktarım Merkezi")        col_a, col_b = st.columns(2)    with col_a:        st.info("1. Adım: Şablonu İndirin")        # Detaylı Sütunlar        cols = ['Ad Soyad', 'Sınıf', 'TYT_Mat', 'TYT_Turkce', 'TYT_Sosyal', 'TYT_Fen', 'AYT_Mat', 'AYT_Fizik', 'AYT_Kimya', 'AYT_Biyoloji']        df_tmp = pd.DataFrame([['Örnek Öğrenci', '12-SAY', 30, 35, 15, 12, 25, 10, 11, 9]], columns=cols)        st.download_button("📥 Excel Şablonu (.csv)", df_tmp.to_csv(index=False).encode('utf-8-sig'), "focus_sablon.csv", "text/csv")            with col_b:        st.info("2. Adım: Veri Yükleyin")                # APPLE NUMBERS UYARISI        st.markdown("""        <div class="warning-box">        ⚠️ <b>Önemli Not:</b> Apple Numbers (.numbers) dosyaları desteklenmez.         Lütfen dosyanızı Numbers uygulamasında <b>Dosya > Dışa Aktar > Excel</b> yolunu izleyerek dönüştürün.        </div>        """, unsafe_allow_html=True)                uploaded_file = st.file_uploader("Dosyayı buraya bırakın (.csv veya .xlsx)", type=['csv', 'xlsx'])                if uploaded_file:            try:                if uploaded_file.name.endswith('.csv'):                    df = pd.read_csv(uploaded_file)                else:                    df = pd.read_excel(uploaded_file)                st.success(f"✅ {len(df)} öğrenci verisi başarıyla analiz edildi!")                st.dataframe(df.head(3), use_container_width=True)            except Exception as e:                st.error("Dosya okunurken bir hata oluştu. Lütfen şablonun bozulmadığından emin olun.")def coach_panel():    st.title("👨‍🏫 Koç Paneli")    st.write("Sınıf Analizi ve Öğrenci Takibi")    # Simüle tablo    st.table(pd.DataFrame({        'Öğrenci': ['Deniz Y.', 'Selin D.'],        'TYT Net': [92.5, 104.0],        'AYT Net': [62.0, 74.5],        'AI Tahmini': [412.4, 465.8]    }))def student_panel():    st.title("🚀 Öğrenci Navigasyonu")    score = calculate_detailed_score({'TYT_Mat': 32, 'TYT_Turkce': 36, 'AYT_Mat': 30, 'AYT_Fizik': 12})        c1, c2 = st.columns([1, 2])    with c1:        st.metric("Tahmini Puanın", f"{score}", "+12.4")        st.write("🎯 Hedef: Ege Bilgisayar")        st.progress(85)    with c2:        st.subheader("📺 Bu Haftaki Eksik Giderme Kampın")        st.video("https://www.youtube.com/watch?v=dQw4w9WgXcQ")# --- 4. ANA AKIŞ ---if 'role' not in st.session_state:    login_screen()else:    st.sidebar.title("FOCUS AI")    if st.sidebar.button("🔒 Çıkış"):        del st.session_state.role        st.rerun()        if st.session_state.role == "ADMIN": admin_panel()    elif st.session_state.role == "KOC": coach_panel()    else: student_panel()